// @ts-check
import { AbstractHandler } from './AbstractHandler.js'

/**
 * @typedef {import('../../utils/Command.js').Command} Command
 */

class GetGlobalFieldHandler extends AbstractHandler {
    requiredParametersCount = 1

    constructor() {
        super()
    }

    /**
     * @param {Command} command
     * @returns {any}
     */
    process(command) {
        try {
            this.validate(command, this.requiredParametersCount, this.constructor.name)
            const { payload } = command
            const fieldName = payload[0]
            /** @type {Record<string, any>} */
            const globalScope = /** @type {any} */ (globalThis)

            if (fieldName in globalScope && typeof globalScope[fieldName] !== 'function') {
                return globalScope[fieldName]
            } else {
                const fields = Object.getOwnPropertyNames(globalScope).filter(
                    (property) => typeof globalScope[property] !== 'function'
                )
                let message = `Field ${fieldName} not found in global. Available fields:\n`
                fields.forEach((field) => {
                    message += `${field}\n`
                })
                throw new Error(message)
            }
        } catch (error) {
            throw this.process_stack_trace(error, this.constructor.name)
        }
    }
}

export { GetGlobalFieldHandler }
